import React, { useState, useEffect } from 'react';
import axios from 'axios';

function Admin() {
  const [requests, setRequests] = useState([]);
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [password, setPassword] = useState('');
  const adminPassword = "admin123";

  const fetchData = async () => {
    try {
      const res = await axios.get('http://localhost:5000/api/requests');
      setRequests(res.data);
    } catch (err) { console.error("Error fetching data:", err); }
  };

  useEffect(() => { if (isLoggedIn) fetchData(); }, [isLoggedIn]);

  const handleLogin = (e) => {
    e.preventDefault();
    if (password === adminPassword) setIsLoggedIn(true);
    else alert("Wrong Password!");
  };

  // अपडेट फंक्शन - जे आता १००% काम करेल
  const handleUpdate = async (id) => {
    const updatedStatus = document.getElementById(`status-${id}`).value;
    const updatedProgress = document.getElementById(`progress-${id}`).value;
    const updatedPayment = document.getElementById(`pay-${id}`).value;

    try {
      const res = await axios.put(`http://localhost:5000/api/update-status/${id}`, {
        status: updatedStatus,
        progress: updatedProgress,
        paymentStatus: updatedPayment
      });

      if (res.status === 200) {
        alert("✅ Project Updated Successfully!");
        fetchData(); // टेबल रिफ्रेश करा
      }
    } catch (err) {
      console.error("Update error:", err);
      alert("❌ Update failed! Check if Backend is running.");
    }
  };

  const handleDelete = async (id) => {
    if (window.confirm("Delete this request?")) {
      await axios.delete(`http://localhost:5000/api/delete-request/${id}`);
      fetchData();
    }
  };

  if (!isLoggedIn) {
    return (
      <div className="container py-5 mt-5">
        <div className="row justify-content-center">
          <div className="col-md-4 card shadow-lg p-4 border-0 text-center">
            <h3>Admin Login</h3>
            <form onSubmit={handleLogin}>
              <input type="password" placeholder="Password" className="form-control mb-3" value={password} onChange={(e) => setPassword(e.target.value)} required />
              <button className="btn btn-dark w-100 fw-bold">Login</button>
            </form>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="container py-5">
      <h2 className="fw-bold text-center mb-4 text-primary">Admin Dashboard</h2>
      <div className="table-responsive shadow-lg rounded-4 p-3 bg-white">
        <table className="table table-hover align-middle border">
          <thead className="table-dark text-center">
            <tr>
              <th>Client</th>
              <th>Payment Status</th>
              <th>Progress (%)</th>
              <th>Work Status</th>
              <th>Action</th>
            </tr>
          </thead>
          <tbody className="text-center">
            {requests.map((req) => (
              <tr key={req._id}>
                <td className="fw-bold">{req.fullName}</td>
                <td>
                  <select id={`pay-${req._id}`} className="form-select form-select-sm" defaultValue={req.paymentStatus}>
                    <option value="Unpaid">Unpaid</option>
                    <option value="Paid">Paid</option>
                  </select>
                </td>
                <td>
                  <input 
                    type="number" 
                    id={`progress-${req._id}`} 
                    className="form-control form-control-sm mx-auto" 
                    defaultValue={req.progress} 
                    min="0" max="100" 
                    style={{ width: '80px' }} 
                  />
                </td>
                <td>
                  <select id={`status-${req._id}`} className="form-select form-select-sm" defaultValue={req.status}>
                    <option value="Pending">Pending</option>
                    <option value="In Progress">In Progress</option>
                    <option value="Completed">Completed</option>
                  </select>
                </td>
                <td>
                  <div className="btn-group">
                    <button className="btn btn-success btn-sm px-3" onClick={() => handleUpdate(req._id)}>Update</button>
                    <button className="btn btn-outline-danger btn-sm" onClick={() => handleDelete(req._id)}>Delete</button>
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

export default Admin;
